function unfoldIcs(text) {
  return text.replace(/\r?\n[ \t]/g, '');
}

function getValue(block, name) {
  const regex = new RegExp('^' + name + '(?:;[^:]*)?:(.*)$', 'mi');
  const match = block.match(regex);
  return match ? match[1].trim() : '';
}

function parseDate(value) {
  if (!value) return null;

  const clean = value.replace('Z', '');
  return `${clean.slice(0,4)}-${clean.slice(4,6)}-${clean.slice(6,8)}T${clean.slice(9,11) || '00'}:${clean.slice(11,13) || '00'}:${clean.slice(13,15) || '00'}+02:00`;
}

const item = $input.first();

if (!item.binary) {
  throw new Error("Aucun fichier reçu. Vérifie le Webhook + curl -F.");
}

const binaryKey = Object.keys(item.binary)[0];

if (!binaryKey) {
  throw new Error("Aucun fichier binary trouvé.");
}

const binaryData = item.binary[binaryKey];

if (!binaryData.data) {
  throw new Error("Le fichier est reçu mais il n'y a pas de data.");
}

const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const icsText = unfoldIcs(buffer.toString('utf-8'));

const blocks = icsText.match(/BEGIN:VEVENT[\s\S]*?END:VEVENT/g) || [];

const events = blocks.map(block => {
  const uid = getValue(block, 'UID');
  const title = getValue(block, 'SUMMARY') || '(Sans titre)';
  const description = getValue(block, 'DESCRIPTION');
  const location = getValue(block, 'LOCATION');
  const dtstart = getValue(block, 'DTSTART');
  const dtend = getValue(block, 'DTEND');
  const rrule = getValue(block, 'RRULE');

  return {
    uid: uid || `${title}-${dtstart}`,
    title,
    description,
    location,
    start_time: parseDate(dtstart),
    end_time: parseDate(dtend),
    is_recurring: !!rrule,
    rrule,
    raw_start: dtstart,
    raw_end: dtend
  };
});

return events.map(e => ({ json: e }));

const HORIZON_DAYS = 365;
const MAX_OCCURRENCES = 60;

function addDays(date, days) {
  const d = new Date(date);
  d.setDate(d.getDate() + days);
  return d;
}

function makeUid(masterUid, date) {
  return `${masterUid}_${date.toISOString().slice(0, 10)}`;
}

const output = [];
const horizon = new Date(Date.now() + HORIZON_DAYS * 86400000);

for (const item of $input.all()) {
  const e = item.json;

  if (!e.is_recurring || !e.rrule) {
    output.push({ json: e });
    continue;
  }

  const start = new Date(e.start_time);
  const end = new Date(e.end_time);
  const duration = end - start;

  let current = new Date(start);
  let count = 0;

  while (current <= horizon && count < MAX_OCCURRENCES) {
    const occEnd = new Date(current.getTime() + duration);

    output.push({
      json: {
        uid: makeUid(e.uid, current),
        master_uid: e.uid,
        title: e.title,
        description: e.description,
        location: e.location,
        start_time: current.toISOString(),
        end_time: occEnd.toISOString(),
        is_recurring: true,
        rrule: e.rrule
      }
    });

    current = addDays(current, 7);
    count++;
  }
}

return output;

const events = $input.all().map(item => ({
  uid: item.json.uid,
  title: item.json.title,
  start_time: item.json.start_time,
  end_time: item.json.end_time,
  location: item.json.location || '',
  description: item.json.description || '',
}));

return [{ json: { events } }];
